# Итератор через класс
class MyIterator:
    def __init__(self, max_value):
        self.current = 0
        self.max_value = max_value

    def __iter__(self):
        return self

    def __next__(self):
        if self.current < self.max_value:
            result = self.current
            self.current += 1
            return result
        raise StopIteration

# Генератор
def my_generator(max_value):
    current = 0
    while current < max_value:
        yield current
        current += 1

for v in my_generator(5):
    print(v)

def log_decorator(func):
    def wrapper(*args, **kwargs):
        print(f'Вызов функции {func.__name__}')
        result = func(*args, **kwargs)
        print(f'Результат: {result}')
        return result
    return wrapper

@log_decorator
def add(a, b):
    return a + b

add(2, 3)
# Вызов функции add
# Результат: 5

def add(x: int, y: int) -> int:
