from typing import Optional, List

def process(items: List[str], limit: Optional[int] = None) -> List[str]:
    return items[:limit]

class Person:
    def __init__(self, name, age):
        self.name = name
        self.age = age

    def __str__(self):
        return f'Person(name={self.name}, age={self.age})'

    def __repr__(self):
        return f"Person('{self.name}', {self.age})"

p = Person('Alice', 30)
print(p)       # Person(name=Alice, age=30)
print(repr(p)) # Person('Alice', 30)

class A:
    def greet(self):
        print('Class A')

class B(A):
    def greet(self):
        print('Class B')
        super().greet()

class D(B):
    def greet(self):
        print('Class D')
        super().greet()

d = D()
d.greet()
# Class D
# Class B
# Class A

class MyClass:
    class_variable = 0

    @classmethod
    def increment(cls):
        cls.class_variable += 1  # доступ к классу через cls

    @staticmethod
    def multiply(a, b):
        return a * b  # нет доступа к cls или self

MyClass.increment()
MyClass.multiply(3, 4)

